parameters.text:
=Analyse this meeting and take all necessary actions using your tools.

Meeting: {{ $json.meeting_title }}
Date: {{ $json.meeting_date }}
Organizer: {{ $json.organizer.name }} <{{ $json.organizer.email }}>

Attendees:
{{ $json.attendees.map(a => '- ' + a.name + ' <' + a.email + '>' + (a.is_external ? ' [EXTERNAL ' + a.company + ']' : ' [Internal]')).join('\n') }}

Full Transcript:
{{ $json.transcript }}

Steps you MUST complete:
1. Call check_blocker_history for each blocker mentioned
2. Call send_action_email once per unique action item owner
3. Call schedule_followup_meeting if a follow-up was agreed
4. Return ONLY the final JSON object

parameters.jsCode:
const input = $input.first().json;
const topic = (input.topic || input.query || '').toLowerCase();
const history = [
  { date: '2026-04-15', topic: 'bosch api documentation', occurrences: 1, impact: 'Firmware integration blocked 2 weeks' },
  { date: '2026-05-01', topic: 'bosch api documentation delay', occurrences: 2, impact: 'Integration testing delayed, sprint missed' },
  { date: '2026-04-08', topic: 'imu sensor calibration drift', occurrences: 1, impact: 'Precision targeting off by 3.1mm' },
  { date: '2026-05-15', topic: 'sensor calibration imu drift', occurrences: 1, impact: 'Precision targeting off by 2.8mm' },
  { date: '2026-05-20', topic: 'power consumption regression', occurrences: 1, impact: 'Build 2.3 exceeded 280W power budget' }
];
const matches = history.filter(h => topic.split(' ').some(w => w.length > 3 && h.topic.includes(w)));
if (matches.length > 0) {
  const total = matches.reduce((s, m) => s + m.occurrences, 0) + 1;
  return JSON.stringify({ is_recurring: true, total_occurrences: total, first_seen: matches[matches.length-1].date, last_seen: matches[0].date, pattern: 'RECURRING BLOCKER seen ' + total + ' times', historical_impact: matches.map(m => m.impact).join(' | '), recommendation: 'Escalation recommended' });
}
return JSON.stringify({ is_recurring: false, total_occurrences: 1, pattern: 'First occurrence', recommendation: 'Monitor' });

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({ success: true, status: 'Meeting queued: ' + (d.title || 'Follow-up') + ' on ' + (d.start_datetime || 'TBD'), note: 'Will be created after human approval' });

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
return JSON.stringify({ success: true, status: 'Email queued for ' + (d.recipient_name || 'team member'), note: 'Will be sent after human approval' });

const raw = $input.first().json.output || '';
let parsed;
try {
  let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  const start = text.indexOf('{'); const end = text.lastIndexOf('}');
  if (start !== -1 && end > start) { parsed = JSON.parse(text.slice(start, end + 1)); }
  else { throw new Error('No JSON found'); }
} catch(e) {
  parsed = { meeting_summary: 'Parse error', action_items: [], external_participants_detected: false, blockers: [], follow_up_meeting: null, risk_flags: ['Parse error: ' + e.message] };
}
return [{ json: parsed }];

const data = $input.first().json;
const items = data.action_items || [];
const followup = data.follow_up_meeting || null;
const externals = data.external_participants || [];
const hasExternal = data.external_participants_detected;
const blockers = (data.blockers || []).filter(b => b.is_recurring);
const risks = data.risk_flags || [];
const rawApprove = $execution.resumeUrl + '?approved=true';
const rawReject = $execution.resumeUrl + '?approved=false';
const resumeUrl = 'http://localhost:8080?action=approve&n8n=' + encodeURIComponent(rawApprove);
const rejectUrl = 'http://localhost:8080?action=reject&n8n=' + encodeURIComponent(rawReject);
// Raw URLs exposed for the web demo page to call directly
const n8nApproveUrl = rawApprove;
const n8nRejectUrl = rawReject;

// Priority colours
const priorityColour = { critical: '#dc3545', high: '#fd7e14', medium: '#ffc107', low: '#6c757d' };

// Build action items HTML
let itemsHtml = '';
items.forEach((item, i) => {
  const isExt = externals.some(e => e.toLowerCase().includes(item.owner_name.toLowerCase().split(' ')[0]));
  const pColour = priorityColour[item.priority] || '#6c757d';
  itemsHtml += '<div style="border:1px solid #e0e0e0;border-radius:6px;padding:12px;margin:6px 0;background:#fafafa">';
  itemsHtml += '<p style="margin:0 0 4px 0"><b>Email ' + (i+1) + ' &rarr; ' + item.owner_name + '</b>';
  if (isExt) itemsHtml += ' <span style="background:#dc3545;color:white;font-size:11px;padding:2px 6px;border-radius:3px">EXTERNAL</span>';
  itemsHtml += '</p>';
  itemsHtml += '<p style="margin:0 0 4px 0;color:#555;font-size:13px">' + item.owner_email + '</p>';
  itemsHtml += '<p style="margin:0 0 4px 0"><b>Task:</b> ' + item.task + '</p>';
  itemsHtml += '<p style="margin:0"><b>Deadline:</b> ' + item.deadline + ' &nbsp; <b style="color:' + pColour + '">Priority: ' + item.priority.toUpperCase() + '</b>';
  if (item.depends_on) itemsHtml += ' &nbsp; <span style="color:#666">Depends on: ' + item.depends_on + '</span>';
  itemsHtml += '</p></div>';
});

// Follow-up meeting HTML
let meetingHtml = '';
if (followup) {
  meetingHtml = '<div style="border:1px solid #0d6efd;border-radius:6px;padding:12px;margin:6px 0;background:#f0f4ff">';
  meetingHtml += '<p style="margin:0 0 4px 0"><b>Teams Meeting: ' + followup.title + '</b></p>';
  meetingHtml += '<p style="margin:0 0 4px 0">Date: <b>' + followup.date + ' at ' + followup.time + '</b> (' + followup.duration_minutes + ' min)</p>';
  meetingHtml += '<p style="margin:0">Agenda: ' + followup.agenda + '</p>';
  meetingHtml += '</div>';
}

// Blockers HTML
let blockersHtml = '';
if (blockers.length > 0) {
  blockersHtml = '<h4 style="color:#dc3545">Recurring Blockers Detected</h4>';
  blockers.forEach(b => {
    blockersHtml += '<p style="margin:4px 0">&#8226; <b>' + b.description + '</b> (seen ' + b.occurrences + ' times) &mdash; owner: ' + b.owner + '</p>';
  });
}

// Risk flags HTML
let risksHtml = '';
if (risks.length > 0) {
  risksHtml = '<h4 style="color:#fd7e14">Risk Flags</h4>';
  risks.forEach(r => { risksHtml += '<p style="margin:4px 0">&#8226; ' + r + '</p>'; });
}

// External warning banner
let warningHtml = '';
if (hasExternal) {
  warningHtml = '<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:6px;padding:12px;margin-bottom:16px">';
  warningHtml += '<b>External participants detected:</b> ' + externals.join(', ') + '<br>';
  warningHtml += '<span style="font-size:13px">These individuals will receive action item emails if you approve.</span>';
  warningHtml += '</div>';
}

// Full email
let html = '<div style="font-family:Arial,sans-serif;max-width:640px;color:#1a1a1a">';
html += '<h2 style="color:#1a1a2e;margin-bottom:4px">NEURA AI Meeting Agent</h2>';
html += '<h3 style="color:#e63946;margin-top:0">Review &amp; Approve Before Sending</h3>';
html += warningHtml;
html += '<h4 style="border-bottom:1px solid #e0e0e0;padding-bottom:6px">Meeting Summary</h4>';
html += '<p>' + (data.meeting_summary || '') + '</p>';
html += '<h4 style="border-bottom:1px solid #e0e0e0;padding-bottom:6px">Action Emails to Send (' + items.length + ')</h4>';
html += itemsHtml;
if (meetingHtml) {
  html += '<h4 style="border-bottom:1px solid #e0e0e0;padding-bottom:6px">Teams Meeting to Create</h4>';
  html += meetingHtml;
}
if (blockersHtml) html += blockersHtml;
if (risksHtml) html += risksHtml;
html += '<br><hr style="border:none;border-top:1px solid #e0e0e0">';
html += '<p><b>If you approve:</b> ' + items.length + ' personalised emails will be sent and the Teams meeting will be created — all in the next 10 seconds.</p>';
html += '<table style="margin-top:12px"><tr>';
html += '<td><a href="' + resumeUrl + '" style="background:#28a745;color:white;padding:14px 36px;text-decoration:none;border-radius:6px;font-size:16px;font-weight:bold;display:inline-block">Approve &amp; Send All</a></td>';
html += '<td style="width:16px"></td>';
html += '<td><a href="' + rejectUrl + '" style="background:#dc3545;color:white;padding:14px 36px;text-decoration:none;border-radius:6px;font-size:16px;font-weight:bold;display:inline-block">Reject</a></td>';
html += '</tr></table>';
html += '<br><hr style="border:none;border-top:1px solid #e0e0e0"><p style="color:#999;font-size:12px"><i>NEURA AI Meeting Agent | Powered by Futurice</i></p>';
html += '</div>';

const subject = '[Review Required] ' + items.length + ' action items from: ' + (data.meeting_summary ? data.meeting_summary.split('.')[0] : 'Meeting') + (hasExternal ? ' — External participants detected' : '');

return [{ json: { subject, html, resume_url: resumeUrl, reject_url: rejectUrl, n8n_approve_url: n8nApproveUrl, n8n_reject_url: n8nRejectUrl, item_count: items.length, action_items: items, follow_up_meeting: followup, meeting_summary: data.meeting_summary, external_participants: externals, has_external: hasExternal } }];

const data = $('Parse Agent Output').item.json;
const items = data.action_items || [];
if (items.length === 0) return [{ json: { status: 'no_items' } }];
return items.map(item => ({ json: item }));

const data = $('Parse Agent Output').item.json;
const items = data.action_items || [];
const followup = data.follow_up_meeting || null;
const followupDate = followup ? followup.date + ' at ' + followup.time : 'TBD';
const actionEmails = items.map((item, i) => ({
  email_number: i + 1,
  type: 'Action Item Email',
  to: item.owner_email,
  recipient: item.owner_name,
  subject: '[Action Required] ' + item.task + ' due ' + item.deadline,
  priority: item.priority,
  depends_on: item.depends_on
}));
const inviteEmail = followup ? {
  email_number: items.length + 1,
  type: 'Follow-up Meeting Invite',
  title: followup.title,
  date: followup.date + ' at ' + followup.time,
  agenda: followup.agenda,
  attendees: followup.attendees
} : null;
const all = inviteEmail ? [...actionEmails, inviteEmail] : actionEmails;
return all.map(e => ({ json: e }));
